-- Events table: source of truth for time entries (date, name, category, length_hours)
CREATE TABLE IF NOT EXISTS "events" (
  "id" integer PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  "date" text NOT NULL,
  "name" text NOT NULL,
  "category" text NOT NULL,
  "length_hours" real NOT NULL,
  "source_type" text NOT NULL DEFAULT 'manual',
  "source_id" text NOT NULL,
  "created_at" timestamp with time zone DEFAULT now() NOT NULL,
  "updated_at" timestamp with time zone DEFAULT now() NOT NULL,
  CONSTRAINT "events_date_source_type_source_id_unique" UNIQUE("date","source_type","source_id")
);

-- Backfill from work_segments into events only if that table exists
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema = 'public' AND table_name = 'work_segments') THEN
    INSERT INTO events (date, name, category, length_hours, source_type, source_id, created_at, updated_at)
    SELECT
      ws.date,
      COALESCE(ws.title, 'Event'),
      ws.category,
      ws.duration_minutes / 60.0,
      'google',
      ws.calendar_id || ':' || ws.external_id,
      COALESCE(ws.synced_at, now()),
      now()
    FROM work_segments ws
    ON CONFLICT (date, source_type, source_id) DO NOTHING;
  END IF;
END $$;

