-- Backfill from daily_totals.minutes_by_category into events (one event per category per day)
DO $$
BEGIN
  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'daily_totals' AND column_name = 'minutes_by_category'
  ) THEN
    INSERT INTO events (date, name, category, length_hours, source_type, source_id, created_at, updated_at)
    SELECT
      d.date,
      cat.key,
      cat.key,
      (cat.value::numeric / 60.0),
      'manual',
      'dt-' || d.date || '-' || regexp_replace(regexp_replace(cat.key, '\s+', '-', 'g'), '/', '-'),
      now(),
      now()
    FROM daily_totals d,
    LATERAL jsonb_each_text(COALESCE(d.minutes_by_category, '{}'::jsonb)) AS cat(key, value)
    WHERE d.minutes_by_category IS NOT NULL
      AND jsonb_typeof(d.minutes_by_category) = 'object'
      AND cat.value ~ '^\d+\.?\d*$'
    ON CONFLICT (date, source_type, source_id) DO NOTHING;
  END IF;
END $$;

