-- Slim daily_totals: drop derived columns (totals now come from events)
ALTER TABLE "daily_totals" DROP COLUMN IF EXISTS "total_minutes";
ALTER TABLE "daily_totals" DROP COLUMN IF EXISTS "minutes_by_category";

-- Remove work_segments (replaced by events)
DROP TABLE IF EXISTS "work_segments";
